mapper.select:

select lt_num, lt_title, lt_content, lt_regDate, lt_startDate, lt_endDate, lt_jobType, lt_status, lt_views
from lecRecruit
where lt_num = #{lt_num}

mapper.update:

update lecRecruit set
lt_status = #{lt_status}
where lt_num = #{lt_num}


update lecRecruit set
lt_views = lt_views + 1
where lt_num = #{lt_num}
